//
// The build-time preset-bundle codegen (see \`../scripts/generate_preset_bundles.ts\`)
// reads this file's raw text, esbuilds it into an IIFE with \`figma:motion\`
// resolved, and emits both strings into \`../generated/corner_radius.generated.ts\`.
// The generated module is what runtime code consumes \u2014 never import this file
// directly from production code paths.
//
// This file is excluded from the share/motion \`ts_project\` compilation \u2014 it's
// only an input to the codegen tool, evaluated inside the QuickJS / iframe
// sandbox at runtime.

import { animate, defineProperties, EasingType, tween } from 'figma:motion'

import type { PresetArgs } from './preset_types'

// Field names must match the contract in
// \`code-components-transpiler/shared/src/motion_constants.ts\` \u2014 any value not
// recognized there causes \`animate()\` to throw "unknown or non-keyframeable
// property" at materialization time.
const CORNER_FIELD_MAP: Record<string, string> = {
  all: 'cornerRadius',
  topLeft: 'rectangleTopLeftCornerRadius',
  topRight: 'rectangleTopRightCornerRadius',
  bottomLeft: 'rectangleBottomLeftCornerRadius',
  bottomRight: 'rectangleBottomRightCornerRadius',
}

const CORNER_KEYS = ['all', 'topLeft', 'topRight', 'bottomLeft', 'bottomRight'] as const
type CornerKey = (typeof CORNER_KEYS)[number]

export default function preset({
  type,
  corner,
  amount,
  allStartFrame,
  allEndFrame,
  topLeftStartFrame,
  topLeftEndFrame,
  topRightStartFrame,
  topRightEndFrame,
  bottomLeftStartFrame,
  bottomLeftEndFrame,
  bottomRightStartFrame,
  bottomRightEndFrame,
  duration,
  easing,
  target,
}: PresetArgs) {
  const selectedCorner: CornerKey = (corner as CornerKey) || 'all'

  function getFromTo(cornerKey: CornerKey): [number, number] {
    if (type === 'custom') {
      switch (cornerKey) {
        case 'topLeft':
          return [topLeftStartFrame, topLeftEndFrame]
        case 'topRight':
          return [topRightStartFrame, topRightEndFrame]
        case 'bottomLeft':
          return [bottomLeftStartFrame, bottomLeftEndFrame]
        case 'bottomRight':
          return [bottomRightStartFrame, bottomRightEndFrame]
        case 'all':
        default:
          return [allStartFrame, allEndFrame]
      }
    }
    if (type === 'roundOut') return [amount, 0]
    return [0, amount]
  }

  // Always emit all five corner tracks so their KEYFRAME_TRACK GUIDs survive \`corner\` toggles. The
  // C++ side honors \`enabled=false\` by marking the track invisible.
  const definition: Record<string, unknown> = {}
  for (const cornerKey of CORNER_KEYS) {
    const fieldName = CORNER_FIELD_MAP[cornerKey]
    const enabled = cornerKey === selectedCorner
    const [from, to] = getFromTo(cornerKey)
    definition[fieldName] = tween({
      mode: 'offset',
      timelinePosition: 0,
      duration,
      from,
      to,
      easing,
      enabled,
    })
  }

  return [animate(target, definition)]
}

